import React, { useState, useRef, useEffect } from "react";
import ReactQuill from "react-quill";
import "react-quill/dist/quill.snow.css";
import { Ic, ICONS } from "../components/UI";

// ── TEMPLATES DATA ────────────────────────────────────────────────────────
const TEMPLATES_DATA = [
  {
    category: "Supreme Court",
    desc: "SLPs, Civil Appeals, Art. 32 Writs, Review & Curative",
    count: "6 templates",
    icon: "book",
    items: [
      { name: "Art. 32 Petition", desc: "Supreme Court writ for enforcement of fundamental rights", content: "<h3 style='text-align: center'>IN THE SUPREME COURT OF INDIA</h3><p style='text-align: center'>ORIGINAL JURISDICTION</p><p style='text-align: center'>WRIT PETITION (CIVIL/CRIMINAL) NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>PETITION UNDER ARTICLE 32 OF THE CONSTITUTION OF INDIA FOR ISSUANCE OF A WRIT IN THE NATURE OF MANDAMUS/HABEAS CORPUS/CERTIORARI.</strong></p><br/><p>TO,<br/>HON'BLE THE CHIEF JUSTICE OF INDIA AND HIS COMPANION JUDGES OF THE SUPREME COURT OF INDIA</p><p>The humble petition of the Petitioner above named.</p><p>MOST RESPECTFULLY SHOWETH:</p><p>1. That the Petitioner is a citizen of India...</p>" },
      { name: "SLP", desc: "Appeal to Supreme Court against High Court orders", content: "<h3 style='text-align: center'>IN THE SUPREME COURT OF INDIA</h3><p style='text-align: center'>APPELLATE JURISDICTION</p><p style='text-align: center'>SPECIAL LEAVE PETITION NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>PETITION UNDER ARTICLE 136 OF THE CONSTITUTION OF INDIA SEEKING SPECIAL LEAVE TO APPEAL.</strong></p><br/><p>TO,<br/>HON'BLE THE CHIEF JUSTICE OF INDIA AND HIS COMPANION JUDGES OF THE SUPREME COURT OF INDIA</p><p>The humble petition of the Petitioner above named.</p><p>MOST RESPECTFULLY SHOWETH:</p><p>1. That the present petition is being filed against the final judgment and order dated ________ passed by the Hon'ble High Court...</p>" },
      { name: "SLP (Civil)", desc: "Appeal to Supreme Court in civil matters under Article 136", content: "<h3 style='text-align: center'>IN THE SUPREME COURT OF INDIA</h3><p style='text-align: center'>CIVIL APPELLATE JURISDICTION</p><p style='text-align: center'>SPECIAL LEAVE PETITION (CIVIL) NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>PETITION UNDER ARTICLE 136 OF THE CONSTITUTION OF INDIA.</strong></p>" },
      { name: "SLP (Criminal)", desc: "Appeal to Supreme Court in criminal matters under Article 136", content: "<h3 style='text-align: center'>IN THE SUPREME COURT OF INDIA</h3><p style='text-align: center'>CRIMINAL APPELLATE JURISDICTION</p><p style='text-align: center'>SPECIAL LEAVE PETITION (CRIMINAL) NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>State of ________ ... Respondent</p><br/><p><strong>PETITION UNDER ARTICLE 136 OF THE CONSTITUTION OF INDIA.</strong></p>" },
      { name: "Civil Appeal", desc: "Appeal in civil matters to Supreme Court after leave granted", content: "<h3 style='text-align: center'>IN THE SUPREME COURT OF INDIA</h3><p style='text-align: center'>CIVIL APPELLATE JURISDICTION</p><p style='text-align: center'>CIVIL APPEAL NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Appellant Name] ... Appellant</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>CIVIL APPEAL UNDER ________.</strong></p>" },
      { name: "Curative Petition", desc: "Last remedy in Supreme Court after review dismissed", content: "<h3 style='text-align: center'>IN THE SUPREME COURT OF INDIA</h3><p style='text-align: center'>INHERENT JURISDICTION</p><p style='text-align: center'>CURATIVE PETITION NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>CURATIVE PETITION UNDER ARTICLE 137 OF THE CONSTITUTION OF INDIA READ WITH ORDER XLVIII OF THE SUPREME COURT RULES.</strong></p>" }
    ]
  },
  {
    category: "High Court",
    desc: "Writ Petitions, Bail, Quashing, Revision, Contempt",
    count: "6 templates",
    icon: "doc",
    items: [
      { name: "Writ Petition", desc: "High Court writ for fundamental rights, service matters, govt action challenges", content: "<h3 style='text-align: center'>IN THE HIGH COURT OF JUDICATURE AT ________</h3><p style='text-align: center'>EXTRAORDINARY WRIT JURISDICTION</p><p style='text-align: center'>WRIT PETITION NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>PETITION UNDER ARTICLE 226 OF THE CONSTITUTION OF INDIA FOR ISSUANCE OF A WRIT IN THE NATURE OF CERTIORARI/MANDAMUS.</strong></p>" },
      { name: "Writ Appeal", desc: "Appeal against single judge writ petition order", content: "<h3 style='text-align: center'>IN THE HIGH COURT OF JUDICATURE AT ________</h3><p style='text-align: center'>APPELLATE JURISDICTION</p><p style='text-align: center'>WRIT APPEAL NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Appellant Name] ... Appellant</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>APPEAL UNDER SECTION _____ AGAINST THE ORDER DATED ________ IN W.P. NO. _____.</strong></p>" },
      { name: "Anticipatory Bail", desc: "Pre-arrest bail under Section 438 CrPC / 482 BNSS", content: "<h3 style='text-align: center'>IN THE HIGH COURT OF JUDICATURE AT ________</h3><p style='text-align: center'>CRIMINAL MISC. BAIL APPLICATION NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Applicant Name] ... Applicant</p><p>VERSUS</p><p>State of ________ ... Respondent</p><br/><p><strong>APPLICATION UNDER SECTION 438 CrPC / 482 BNSS FOR GRANT OF ANTICIPATORY BAIL.</strong></p>" },
      { name: "482 CrPC Petition", desc: "FIR quashing, abuse of process", content: "<h3 style='text-align: center'>IN THE HIGH COURT OF JUDICATURE AT ________</h3><p style='text-align: center'>CRIMINAL MISC. APPLICATION NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>State of ________ ... Respondent</p><br/><p><strong>PETITION UNDER SECTION 482 CrPC / 528 BNSS FOR QUASHING OF FIR NO. _____ DATED ________.</strong></p>" },
      { name: "Revision Petition", desc: "Against lower court orders in criminal matters", content: "<h3 style='text-align: center'>IN THE HIGH COURT OF JUDICATURE AT ________</h3><p style='text-align: center'>CRIMINAL REVISION NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>State of ________ ... Respondent</p><br/><p><strong>CRIMINAL REVISION PETITION UNDER SECTION 397 READ WITH SECTION 401 OF CrPC / 438 READ WITH 442 OF BNSS.</strong></p>" },
      { name: "Review", desc: "Application for review of judgment under Order 47 CPC", content: "<h3 style='text-align: center'>IN THE HIGH COURT OF JUDICATURE AT ________</h3><p style='text-align: center'>REVIEW PETITION NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>REVIEW PETITION UNDER ORDER XLVII RULE 1 OF THE CODE OF CIVIL PROCEDURE, 1908.</strong></p>" }
    ]
  },
  {
    category: "District / Sessions Court",
    desc: "Civil Suits, Bail Applications, Written Statements, IAs",
    count: "4 templates",
    icon: "grid",
    items: [
      { name: "Plaint", desc: "Original suit for civil matters - recovery, declaration, injunction", content: "<h3 style='text-align: center'>IN THE COURT OF CIVIL JUDGE, ________</h3><p style='text-align: center'>CIVIL SUIT NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Plaintiff Name] ... Plaintiff</p><p>VERSUS</p><p>[Defendant Name] ... Defendant</p><br/><p><strong>SUIT FOR RECOVERY OF RS. ________/- (RUPEES ________ ONLY) ALONG WITH INTEREST PENDENTE LITE AND FUTURE INTEREST.</strong></p>" },
      { name: "Written Statement", desc: "Defendant's reply to plaint with preliminary objections", content: "<h3 style='text-align: center'>IN THE COURT OF CIVIL JUDGE, ________</h3><p style='text-align: center'>CIVIL SUIT NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Plaintiff Name] ... Plaintiff</p><p>VERSUS</p><p>[Defendant Name] ... Defendant</p><br/><p><strong>WRITTEN STATEMENT ON BEHALF OF THE DEFENDANT UNDER ORDER VIII RULE 1 CPC.</strong></p><br/><p>PRELIMINARY OBJECTIONS:</p><p>1. That the present suit is not maintainable...</p>" },
      { name: "IA", desc: "Application for stay, injunction, amendment, documents", content: "<h3 style='text-align: center'>IN THE COURT OF CIVIL JUDGE, ________</h3><p style='text-align: center'>INTERLOCUTORY APPLICATION NO. _____ IN CIVIL SUIT NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Plaintiff Name] ... Plaintiff</p><p>VERSUS</p><p>[Defendant Name] ... Defendant</p><br/><p><strong>APPLICATION UNDER ORDER XXXIX RULE 1 & 2 CPC FOR AD-INTERIM INJUNCTION.</strong></p>" },
      { name: "Bail", desc: "Application for regular bail in criminal matters", content: "<h3 style='text-align: center'>IN THE COURT OF DISTRICT & SESSIONS JUDGE, ________</h3><p style='text-align: center'>BAIL APPLICATION NO. _____ OF 20__</p><br/><p>IN THE MATTER OF:</p><p>[Applicant Name] ... Applicant</p><p>VERSUS</p><p>State of ________ ... Respondent</p><br/><p><strong>APPLICATION UNDER SECTION 439 CrPC / 483 BNSS FOR GRANT OF REGULAR BAIL.</strong></p>" }
    ]
  },
  {
    category: "General",
    desc: "Affidavits, Vakalatnama, Court Forms",
    count: "5 templates",
    icon: "file",
    items: [
      { name: "Affidavit", desc: "General purpose affidavit for court proceedings", content: "<h3 style='text-align: center'>AFFIDAVIT</h3><br/><p>I, ________, S/o ________, aged about ________ years, resident of ________, do hereby solemnly affirm and state as under:</p><br/><p>1. That I am the Deponent herein and am fully conversant with the facts and circumstances of the case.</p><p>2. That the contents of the accompanying application are true and correct to the best of my knowledge.</p><br/><br/><p style='text-align: right'><strong>DEPONENT</strong></p><br/><p><strong>VERIFICATION:</strong></p><p>Verified at ________ on this _____ day of ________, 20__, that the contents of the above affidavit are true and correct to my knowledge and nothing material has been concealed therefrom.</p><br/><br/><p style='text-align: right'><strong>DEPONENT</strong></p>" },
      { name: "Counter Affidavit", desc: "Reply affidavit filed by respondent", content: "<h3 style='text-align: center'>BEFORE THE HON'BLE COURT OF ________</h3><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>COUNTER AFFIDAVIT ON BEHALF OF THE RESPONDENT</strong></p><br/><p>I, ________, S/o ________, aged about ________ years, do hereby solemnly affirm and declare as under:</p><p>1. That the averments made in paragraph 1 of the Petition are vehemently denied as false and baseless...</p>" },
      { name: "Rejoinder", desc: "Reply to counter affidavit by petitioner", content: "<h3 style='text-align: center'>BEFORE THE HON'BLE COURT OF ________</h3><br/><p>IN THE MATTER OF:</p><p>[Petitioner Name] ... Petitioner</p><p>VERSUS</p><p>[Respondent Name] ... Respondent</p><br/><p><strong>REJOINDER AFFIDAVIT ON BEHALF OF THE PETITIONER TO THE COUNTER AFFIDAVIT FILED BY THE RESPONDENT</strong></p><br/><p>I, ________, do hereby solemnly affirm and declare as under:</p><p>1. That the contents of the Counter Affidavit are denied, and the contents of the Original Petition are reiterated...</p>" },
      { name: "CA Form 7", desc: "eCourts CA Form 7: application for certified copy from court records", content: "<h3 style='text-align: center'>CA FORM 7</h3><p style='text-align: center'>APPLICATION FOR CERTIFIED COPY</p><br/><p>To,<br/>The Superintendent, Copying Branch,<br/>Court of ________.</p><br/><p>Sir,<br/>Please supply me with a certified copy of the following document(s) in the under-mentioned case:</p><p>Case No: ________</p><p>Parties: ________ vs ________</p><p>Date of Decision/Order: ________</p><p>Document required: ________</p><br/><br/><p style='text-align: right'><strong>Signature of Applicant/Advocate</strong></p>" },
      { name: "Vakalatnama", desc: "Authorization to represent in court proceedings", content: "<h3 style='text-align: center'>VAKALATNAMA</h3><br/><p>IN THE COURT OF ________</p><p>SUIT/APPEAL/PETITION NO. _____ OF 20__</p><br/><p>[Plaintiff/Appellant/Petitioner]</p><p>VERSUS</p><p>[Defendant/Respondent]</p><br/><p>KNOW ALL to whom these present shall come that I/We ________ do hereby appoint ________, Advocate(s) to be my/our Advocate in the above-noted case to appear, act and plead on my/our behalf.</p><br/><p>Date: ________</p><p style='text-align: right'><strong>Client Signature</strong></p><p>ACCEPTED</p><p><strong>Advocate Signature</strong></p>" }
    ]
  }
];

export default function Editor({ t, toast }) {
  const [content, setContent] = useState("");
  const [title, setTitle] = useState("Untitled Document");
  const [showTemplates, setShowTemplates] = useState(false);
  const [selectedCategory, setSelectedCategory] = useState(null);
  const [searchQuery, setSearchQuery] = useState("");
  const quillRef = useRef(null);

  // AI Copilot States
  const [chats, setChats] = useState([
    { role: "assistant", content: "Hi! I'm your legal drafting copilot. I can help you draft clauses, summarize facts, or find legal precedents. What are we working on today?" }
  ]);
  const [chatInput, setChatInput] = useState("");
  const [isChatLoading, setIsChatLoading] = useState(false);

  // Editor configuration
  const modules = {
    toolbar: {
      container: "#ns-toolbar",
    }
  };

  const handleTemplateSelect = (templateContent) => {
    setContent(templateContent);
    setShowTemplates(false);
    toast("Template loaded successfully", "success");
  };

  const insertAIContent = (text) => {
    if (quillRef.current) {
      const editor = quillRef.current.getEditor();
      const range = editor.getSelection(true);
      editor.insertText(range.index, text);
      editor.setSelection(range.index + text.length);
      toast("Clause inserted into document", "success");
    }
  };

  const handleChatSubmit = async (e) => {
    e.preventDefault();
    if (!chatInput.trim()) return;

    const newChat = { role: "user", content: chatInput };
    setChats(prev => [...prev, newChat]);
    setChatInput("");
    setIsChatLoading(true);

    try {
      const res = await fetch("http://localhost:8001/api/editor/copilot", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ prompt: newChat.content, document_context: content })
      });
      const data = await res.json();

      setChats(prev => [...prev, { role: "assistant", content: data.reply }]);
    } catch (err) {
      toast("Failed to connect to AI Copilot", "error");
      setChats(prev => [...prev, { role: "assistant", content: "Sorry, I encountered an error." }]);
    }
    setIsChatLoading(false);
  };

  return (
    <div style={{ display: "flex", height: "calc(100vh - 60px)", overflow: "hidden", background: t.bg }}>
      <style>{`
        /* ── Quill Editor Styles to Match LawCentral ── */
        .ns-editor-wrapper {
          display: flex;
          flex-direction: column;
          flex: 1;
          height: 100%;
          background: ${t.name === "dark" ? "#121212" : "#f5f6f8"};
        }

        /* Toolbar Styling */
        #ns-toolbar {
          border: none !important;
          border-bottom: 1px solid ${t.border} !important;
          background: ${t.surface};
          padding: 12px 24px;
          display: flex;
          align-items: center;
          gap: 4px;
          flex-wrap: wrap;
        }
        #ns-toolbar .ql-picker { color: ${t.text}; }
        #ns-toolbar .ql-stroke { stroke: ${t.sub}; }
        #ns-toolbar .ql-fill { fill: ${t.sub}; }
        #ns-toolbar button:hover .ql-stroke { stroke: ${t.blue}; }
        #ns-toolbar .ql-picker-options { background: ${t.surfaceUp}; border-color: ${t.border}; }

        /* A4 Page Container */
        .ql-container.ql-snow {
          border: none !important;
          flex: 1;
          overflow-y: auto;
          display: flex;
          justify-content: center;
          padding: 40px 0;
        }
        .ql-editor {
          background: white;
          width: 816px; /* A4 Width roughly */
          min-height: 1056px; /* A4 Height roughly */
          padding: 96px; /* Standard 1 inch margins */
          box-shadow: 0 4px 24px rgba(0,0,0,0.06);
          color: black;
          font-family: 'Times New Roman', serif;
          font-size: 16px;
          line-height: 1.6;
        }
        ${t.name === "dark" ? `
          .ql-editor {
            background: #1e1e1e;
            color: #d4d4d4;
            box-shadow: 0 4px 24px rgba(0,0,0,0.5);
          }
        ` : ""}

        .ql-editor p { margin-bottom: 1em; }
        .ql-editor h3 { text-align: center; font-size: 1.2em; font-weight: bold; margin-bottom: 1.5em; text-transform: uppercase; }

        /* Copilot Sidebar */
        .ns-copilot {
          width: 320px;
          background: ${t.surface};
          border-right: 1px solid ${t.border};
          display: flex;
          flex-direction: column;
          flex-shrink: 0;
        }

        /* Custom Scrollbar for Chat */
        .ns-chat-scroll::-webkit-scrollbar { width: 4px; }
        .ns-chat-scroll::-webkit-scrollbar-thumb { background: ${t.border}; border-radius: 4px; }
      `}</style>

      {/* LEFT SIDEBAR: AI Copilot */}
      <div className="ns-copilot">
        <div style={{ padding: "20px", borderBottom: `1px solid ${t.border}`, display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{ width: 32, height: 32, borderRadius: 8, background: `linear-gradient(135deg, ${t.blue}, #0d1e5a)`, display: "flex", alignItems: "center", justifyContent: "center" }}>
            <Ic d={ICONS.book} size={16} color="white" />
          </div>
          <div>
            <h3 style={{ margin: 0, fontSize: 16, fontWeight: 700 }}>AI Copilot</h3>
            <div style={{ fontSize: 12, color: t.sub }}>Legal Drafting Assistant</div>
          </div>
        </div>

        <div className="ns-chat-scroll" style={{ flex: 1, overflowY: "auto", padding: 20, display: "flex", flexDirection: "column", gap: 16 }}>
          {chats.map((chat, idx) => (
            <div key={idx} style={{ alignSelf: chat.role === "user" ? "flex-end" : "flex-start", maxWidth: "85%" }}>
              <div style={{ 
                background: chat.role === "user" ? t.blue : t.surfaceUp, 
                color: chat.role === "user" ? "white" : t.text,
                padding: "12px 16px", 
                borderRadius: chat.role === "user" ? "16px 16px 4px 16px" : "16px 16px 16px 4px",
                fontSize: 14,
                lineHeight: 1.5,
                border: chat.role === "assistant" ? `1px solid ${t.border}` : "none"
              }}>
                {chat.content}
              </div>
              {chat.role === "assistant" && idx > 0 && (
                <button 
                  onClick={() => insertAIContent(chat.content)}
                  style={{ background: "transparent", border: "none", color: t.amber, fontSize: 12, fontWeight: 600, marginTop: 6, cursor: "pointer", display: "flex", alignItems: "center", gap: 4 }}
                >
                  <Ic d={ICONS.download} size={12} color={t.amber} /> Insert into Document
                </button>
              )}
            </div>
          ))}
          {isChatLoading && (
            <div style={{ alignSelf: "flex-start", padding: "12px 16px", background: t.surfaceUp, borderRadius: "16px 16px 16px 4px", border: `1px solid ${t.border}` }}>
              <div style={{ display: "flex", gap: 4 }}>
                <span className="ns-dot"></span><span className="ns-dot" style={{animationDelay: "0.2s"}}></span><span className="ns-dot" style={{animationDelay: "0.4s"}}></span>
              </div>
            </div>
          )}
        </div>

        <div style={{ padding: 16, borderTop: `1px solid ${t.border}` }}>
          <form onSubmit={handleChatSubmit} style={{ display: "flex", background: t.surfaceUp, border: `1px solid ${t.border}`, borderRadius: 24, padding: "4px 4px 4px 16px", alignItems: "center" }}>
            <input 
              value={chatInput} 
              onChange={e => setChatInput(e.target.value)}
              placeholder="Ask for clauses, facts..." 
              style={{ flex: 1, background: "transparent", border: "none", color: t.text, outline: "none", fontSize: 14 }}
            />
            <button type="submit" disabled={!chatInput.trim()} style={{ width: 32, height: 32, borderRadius: 16, background: chatInput.trim() ? t.blue : t.border, color: "white", border: "none", display: "flex", alignItems: "center", justifyContent: "center", cursor: chatInput.trim() ? "pointer" : "default", transition: "background 0.2s" }}>
              <Ic d={ICONS.send} size={14} color="white" />
            </button>
          </form>
        </div>
      </div>

      {/* RIGHT SIDE: Main Editor */}
      <div className="ns-editor-wrapper">
        {/* Top Header */}
        <div style={{ height: 64, borderBottom: `1px solid ${t.border}`, background: t.surface, display: "flex", alignItems: "center", justifyContent: "space-between", padding: "0 24px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
            <div style={{ width: 36, height: 36, background: t.surfaceUp, borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center", border: `1px solid ${t.border}` }}>
              <Ic d={ICONS.doc} size={18} color={t.sub} />
            </div>
            <div>
              <input 
                value={title} 
                onChange={e => setTitle(e.target.value)}
                style={{ background: "transparent", border: "none", fontSize: 18, fontWeight: 700, color: t.text, outline: "none", padding: 0, margin: "0 0 2px" }} 
              />
              <div style={{ fontSize: 12, color: t.sub }}>Legal Document • New document</div>
            </div>
          </div>

          <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
            <button onClick={() => setShowTemplates(true)} style={{ display: "flex", alignItems: "center", gap: 8, background: t.surfaceUp, border: `1px solid ${t.border}`, color: t.text, padding: "8px 16px", borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>
              <Ic d={ICONS.grid} size={16} color={t.text} /> Templates
            </button>
            <button style={{ display: "flex", alignItems: "center", gap: 8, background: t.surfaceUp, border: `1px solid ${t.border}`, color: t.text, padding: "8px 16px", borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: "pointer" }}>
              <Ic d={ICONS.download} size={16} color={t.text} /> Export
            </button>
            <button style={{ display: "flex", alignItems: "center", gap: 8, background: t.blue, border: `1px solid ${t.blue}`, color: "white", padding: "8px 24px", borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: "pointer", boxShadow: "0 2px 8px rgba(13,110,253,0.3)" }}>
              <Ic d={ICONS.file} size={16} color="white" /> Save
            </button>
          </div>
        </div>

        {/* Custom Toolbar */}
        <div id="ns-toolbar">
          <select className="ql-font" defaultValue="times">
            <option value="times">Times New Roman</option>
            <option value="arial">Arial</option>
            <option value="sans-serif">Sans Serif</option>
          </select>
          <select className="ql-size" defaultValue="16px">
            <option value="12px">12</option>
            <option value="14px">14</option>
            <option value="16px">16</option>
            <option value="18px">18</option>
            <option value="24px">24</option>
          </select>
          <span className="ql-formats" style={{ marginLeft: 16, marginRight: 16 }}>
            <button className="ql-bold" />
            <button className="ql-italic" />
            <button className="ql-underline" />
            <button className="ql-strike" />
          </span>
          <span className="ql-formats" style={{ marginRight: 16 }}>
            <select className="ql-color" />
            <select className="ql-background" />
          </span>
          <span className="ql-formats" style={{ marginRight: 16 }}>
            <select className="ql-align" />
          </span>
          <span className="ql-formats">
            <button className="ql-list" value="ordered" />
            <button className="ql-list" value="bullet" />
            <button className="ql-indent" value="-1" />
            <button className="ql-indent" value="+1" />
          </span>
        </div>

        {/* Editor Area */}
        <ReactQuill 
          ref={quillRef}
          value={content} 
          onChange={setContent} 
          modules={modules}
          theme="snow"
          placeholder="Start drafting your legal document..."
        />
      </div>

      {/* TEMPLATES MODAL */}
      {showTemplates && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.6)", backdropFilter: "blur(4px)", zIndex: 10000, display: "flex", alignItems: "center", justifyContent: "center", padding: 20 }}>
          <div style={{ width: "100%", maxWidth: 800, background: t.surface, borderRadius: 16, boxShadow: "0 24px 48px rgba(0,0,0,0.2)", display: "flex", flexDirection: "column", maxHeight: "90vh" }}>

            <div style={{ padding: 24, borderBottom: `1px solid ${t.border}`, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                {selectedCategory ? (
                  <button onClick={() => setSelectedCategory(null)} style={{ padding: 8, background: "transparent", border: "none", cursor: "pointer", display: "flex", alignItems: "center" }}>
                    <Ic d={ICONS.chevronLeft} size={20} color={t.text} />
                  </button>
                ) : (
                  <div style={{ padding: 8, background: t.surfaceUp, borderRadius: 8, border: `1px solid ${t.border}` }}>
                    <Ic d={ICONS.doc} size={20} color={t.text} />
                  </div>
                )}
                <div>
                  <h2 style={{ margin: 0, fontSize: 20, fontWeight: 700 }}>{selectedCategory ? selectedCategory.category : "Load Template"}</h2>
                  <div style={{ fontSize: 14, color: t.sub }}>{selectedCategory ? "Select a document to load" : "Search for a template or browse by category"}</div>
                </div>
              </div>
              <button onClick={() => {setShowTemplates(false); setSelectedCategory(null);}} style={{ background: "transparent", border: "none", cursor: "pointer" }}>
                <Ic d={ICONS.x} size={24} color={t.sub} />
              </button>
            </div>

            <div style={{ padding: 24, overflowY: "auto", minHeight: 400 }}>
              {selectedCategory && (
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 24, fontSize: 13, fontWeight: 600 }}>
                  <div style={{ background: t.surfaceUp, padding: "4px 12px", borderRadius: 16, color: t.sub }}>1 Court</div>
                  <Ic d={ICONS.chevronRight} size={14} color={t.sub} />
                  <div style={{ background: `${t.amber}22`, padding: "4px 12px", borderRadius: 16, color: t.amber, border: `1px solid ${t.amber}44` }}>2 Template</div>
                </div>
              )}

              {!selectedCategory ? (
                <>
                  <div style={{ position: "relative", marginBottom: 32 }}>
                    <Ic d={ICONS.search} size={18} color={t.sub} style={{ position: "absolute", left: 16, top: "50%", transform: "translateY(-50%)" }} />
                    <input 
                      placeholder="Search templates... (e.g. Vakalatnama, Writ Petition, Bail)"
                      value={searchQuery}
                      onChange={e => setSearchQuery(e.target.value)}
                      style={{ width: "100%", padding: "16px 16px 16px 48px", borderRadius: 12, border: `1px solid ${t.border}`, background: t.bg, color: t.text, fontSize: 15, outline: "none" }}
                    />
                  </div>

                  <div style={{ display: "flex", alignItems: "center", gap: 16, marginBottom: 24 }}>
                    <div style={{ flex: 1, height: 1, background: t.border }}></div>
                    <div style={{ fontSize: 11, fontWeight: 700, color: t.muted, letterSpacing: 1, textTransform: "uppercase" }}>OR BROWSE BY CATEGORY</div>
                    <div style={{ flex: 1, height: 1, background: t.border }}></div>
                  </div>

                  <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
                    {TEMPLATES_DATA.filter(cat => !searchQuery || cat.items.some(i => i.name.toLowerCase().includes(searchQuery.toLowerCase()))).map((cat, i) => (
                      <button 
                        key={i} 
                        onClick={() => setSelectedCategory(cat)}
                        style={{ padding: 24, borderRadius: 12, border: `1px solid ${t.border}`, background: t.surface, display: "flex", flexDirection: "column", cursor: "pointer", textAlign: "left", transition: "all 0.2s" }}
                        onMouseEnter={e => { e.currentTarget.style.borderColor = t.blue; e.currentTarget.style.background = t.surfaceUp; }}
                        onMouseLeave={e => { e.currentTarget.style.borderColor = t.border; e.currentTarget.style.background = t.surface; }}
                      >
                        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 12 }}>
                          <div style={{ width: 48, height: 48, background: t.surfaceUp, borderRadius: 10, display: "flex", alignItems: "center", justifyContent: "center", border: `1px solid ${t.border}` }}>
                            <Ic d={ICONS[cat.icon]} size={24} color={t.sub} />
                          </div>
                        </div>
                        <h3 style={{ margin: "0 0 8px", fontSize: 18, fontWeight: 700, color: t.text }}>{cat.category}</h3>
                        <div style={{ fontSize: 13, color: t.sub, marginBottom: 16, lineHeight: 1.5, flex: 1 }}>{cat.desc}</div>
                        <div style={{ fontSize: 12, color: t.muted, fontWeight: 600, display: "flex", alignItems: "center", gap: 6 }}>
                          <Ic d={ICONS.doc} size={14} color={t.muted} /> {cat.items.length} templates
                        </div>
                      </button>
                    ))}
                  </div>
                </>
              ) : (
                <div style={{ display: "flex", flexDirection: "column", gap: 1 }}>
                  {selectedCategory.items.map((item, j) => (
                    <button 
                      key={j}
                      onClick={() => handleTemplateSelect(item.content)}
                      style={{ padding: "16px 8px", background: "transparent", border: "none", borderBottom: `1px solid ${t.border}`, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "space-between", textAlign: "left", transition: "background 0.2s" }}
                      onMouseEnter={e => e.currentTarget.style.background = `${t.blue}0a`}
                      onMouseLeave={e => e.currentTarget.style.background = "transparent"}
                    >
                      <div style={{ display: "flex", alignItems: "flex-start", gap: 16 }}>
                        <Ic d={ICONS.doc} size={20} color={t.sub} style={{ marginTop: 2 }} />
                        <div>
                          <div style={{ fontSize: 15, fontWeight: 600, color: t.text, marginBottom: 4 }}>{item.name}</div>
                          <div style={{ fontSize: 13, color: t.sub }}>{item.desc}</div>
                        </div>
                      </div>
                      <Ic d={ICONS.chevronRight} size={18} color={t.sub} />
                    </button>
                  ))}
                </div>
              )}
            </div>

            <div style={{ padding: "16px 24px", borderTop: `1px solid ${t.border}`, display: "flex", justifyContent: "space-between", alignItems: "center", background: t.surfaceUp, borderRadius: "0 0 16px 16px" }}>
              {selectedCategory ? (
                <div style={{ fontSize: 13, color: t.sub }}>Click a template to load it</div>
              ) : (
                <div style={{ fontSize: 13, color: t.sub }}>{TEMPLATES_DATA.reduce((acc, cat) => acc + cat.items.length, 0)} templates • {TEMPLATES_DATA.length} categories</div>
              )}
              <button onClick={() => {
                if (selectedCategory) setSelectedCategory(null);
                else setShowTemplates(false);
              }} style={{ background: "transparent", border: "none", color: t.sub, fontWeight: 600, cursor: "pointer" }}>
                {selectedCategory ? "Back" : "Cancel"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
